  "type": "FLIP_CARD",
  "lessonText": "Explore the key physiological processes that regulate body temperature.",
  "data": {
    "cards": [
      {
        "front": "What is thermoregulation?",
        "back": "The process by which the body maintains its core internal temperature.",
        "icon": "thermometer"
      },
      {
        "front": "Role of the hypothalamus",
        "back": "Acts as the body's thermostat, detecting temperature changes and initiating responses.",
        "icon": "brain"
      },
      {
        "front": "Vasodilation",
        "back": "Widening of blood vessels to increase blood flow and release heat.",
        "icon": "blood-vessel"
      },
      {
        "front": "Vasoconstriction",
        "back": "Narrowing of blood vessels to conserve heat during cold conditions.",
        "icon": "cold"
      }
    ]
  }
}
